INSERT INTO public.game_questions (game_id, question_text, question_type, category, level, options, correct_answer, explanation, points_reward, time_limit_sec, status, version) VALUES
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el río más largo de Colombia?', 'multiple_choice', 'Geografía', 1, '["Río Cauca","Río Magdalena","Río Amazonas","Río Orinoco"]'::jsonb, '"Río Magdalena"'::jsonb, 'El río Magdalena es la principal arteria fluvial de Colombia, cruzando el país de sur a norte.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué ciudad se celebra la Feria de las Flores?', 'multiple_choice', 'Cultura', 1, '["Bogotá","Medellín","Cali","Barranquilla"]'::jsonb, '"Medellín"'::jsonb, 'La Feria de las Flores es el evento tradicional más importante de Medellín, Antioquia.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué baile es considerado el ritmo nacional de Colombia?', 'multiple_choice', 'Cultura', 1, '["Salsa","Vallenato","Cumbia","Joropo"]'::jsonb, '"Cumbia"'::jsonb, 'La cumbia, originaria de la costa caribe, es considerada una de las expresiones musicales más representativas de Colombia.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Quién escribió la novela "Cien años de soledad"?', 'multiple_choice', 'Literatura', 1, '["Jorge Isaacs","Gabriel García Márquez","Álvaro Mutis","Rafael Pombo"]'::jsonb, '"Gabriel García Márquez"'::jsonb, 'Gabo publicó Cien años de soledad en 1967, consolidando el realismo mágico a nivel mundial.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es la flor nacional de Colombia?', 'multiple_choice', 'Naturaleza', 1, '["Rosa","Girasol","Orquídea","Margarita"]'::jsonb, '"Orquídea"'::jsonb, 'La orquídea (Cattleya trianae) es la flor emblemática de Colombia debido a su belleza y variedad en el territorio.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿De qué región es típico el ajiaco?', 'multiple_choice', 'Gastronomía', 1, '["Antioquia","Valle del Cauca","Costa Caribe","Cundinamarca/Bogotá"]'::jsonb, '"Cundinamarca/Bogotá"'::jsonb, 'El ajiaco santafereño es una sopa tradicional originaria de Bogotá y la región cundiboyacense.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué año se firmó la actual Constitución Política de Colombia?', 'multiple_choice', 'Historia', 1, '["1886","1991","2000","1810"]'::jsonb, '"1991"'::jsonb, 'La actual Constitución Política fue promulgada en 1991, reemplazando a la antigua de 1886.', 10, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué comunidad indígena habita principalmente en la Sierra Nevada de Santa Marta?', 'multiple_choice', 'Cultura', 2, '["Wayuu","Koguis","Embera","Guambianos"]'::jsonb, '"Koguis"'::jsonb, 'Los Koguis (o Kággaba) son uno de los grupos indígenas que preservan sus tradiciones milenarias en la Sierra Nevada.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el único país de Suramérica que tiene costas en dos océanos?', 'multiple_choice', 'Geografía', 2, '["Brasil","Venezuela","Colombia","Argentina"]'::jsonb, '"Colombia"'::jsonb, 'Colombia es privilegiada al estar bañada tanto por el Océano Pacífico como por el Mar Caribe (Océano Atlántico).', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué artista colombiano es famoso por sus figuras voluminosas y exageradas?', 'multiple_choice', 'Arte', 2, '["Alejandro Obregón","Fernando Botero","Omar Rayo","David Manzur"]'::jsonb, '"Fernando Botero"'::jsonb, 'Fernando Botero es mundialmente reconocido por el "Boterismo", estilo que exalta el volumen en sus obras.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el Parque Nacional Natural más extenso de Colombia?', 'multiple_choice', 'Naturaleza', 2, '["Tayrona","Chiribiquete","Macarena","Amacayacu"]'::jsonb, '"Chiribiquete"'::jsonb, 'El Parque Nacional Natural Serranía de Chiribiquete es el área protegida más grande del país y Patrimonio de la Humanidad.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué año ocurrió el evento histórico conocido como "El Bogotazo"?', 'multiple_choice', 'Historia', 2, '["1928","1948","1985","1991"]'::jsonb, '"1948"'::jsonb, 'El 9 de abril de 1948, tras el asesinato de Jorge Eliécer Gaitán, se desataron disturbios masivos en Bogotá.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué ingrediente principal distingue al mote de queso?', 'multiple_choice', 'Gastronomía', 2, '["Plátano maduro","Ñame","Yuca","Papa criolla"]'::jsonb, '"Ñame"'::jsonb, 'El mote de queso es una sopa insignia de la Costa Caribe, preparada a base de ñame y queso costeño.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué ciudad es conocida como la "Ciudad Blanca" de Colombia?', 'multiple_choice', 'Cultura', 2, '["Cartagena","Popayán","Villa de Leyva","Santa Marta"]'::jsonb, '"Popayán"'::jsonb, 'Popayán es llamada la "Ciudad Blanca" por sus hermosas fachadas coloniales de color blanco.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué cacique indígena lideró una de las más grandes rebeliones contra los españoles en 1537 en la sabana de Bogotá?', 'multiple_choice', 'Historia', 3, '["Calarcá","Tisquesusa","Gaitana","Tundama"]'::jsonb, '"Tisquesusa"'::jsonb, 'Tisquesusa, zipa de Bacatá, fue un líder muisca que enfrentó la expedición de Gonzalo Jiménez de Quesada.', 30, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el nombre del primer premio Nobel de Colombia?', 'multiple_choice', 'Literatura', 3, '["Juan Manuel Santos","Gabriel García Márquez","Álvaro Mutis","Ninguno"]'::jsonb, '"Gabriel García Márquez"'::jsonb, 'Gabriel García Márquez recibió el Nobel de Literatura en 1982, siendo el primer colombiano en ganar un premio Nobel (antes que Juan Manuel Santos en Paz).', 30, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué departamento se encuentra el Santuario de Flora y Fauna Iguaque, laguna sagrada de los Muiscas?', 'multiple_choice', 'Geografía', 3, '["Cundinamarca","Boyacá","Santander","Tolima"]'::jsonb, '"Boyacá"'::jsonb, 'La Laguna de Iguaque, considerada cuna de la humanidad por los Muiscas, se encuentra cerca de Villa de Leyva, en Boyacá.', 30, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Quién escribió la obra teatral "La cándida Eréndira y su abuela desalmada"?', 'multiple_choice', 'Literatura', 3, '["Álvaro Cepeda Samudio","Gabriel García Márquez","Andrés Caicedo","José Eustasio Rivera"]'::jsonb, '"Gabriel García Márquez"'::jsonb, 'Gabo escribió este cuento que luego fue adaptado tanto al teatro como al cine.', 30, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué ritmo musical es patrimonio inmaterial originario de la región del Pacífico sur (Nariño, Cauca, Valle)?', 'multiple_choice', 'Cultura', 3, '["Bullerengue","Currulao","Bambuco","Mapalé"]'::jsonb, '"Currulao"'::jsonb, 'El currulao es la danza de ancestro africano más representativa del litoral Pacífico sur colombiano.', 30, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Tratado Mallarino-Bidlack" firmado en 1846 fue crucial para la historia de:', 'multiple_choice', 'Historia', 3, '["Independencia de Venezuela","Separación de Panamá","Guerra de los Mil Días","Frontera con Perú"]'::jsonb, '"Separación de Panamá"'::jsonb, 'Este tratado garantizaba el derecho de tránsito de EE.UU. por el istmo, lo cual influyó posteriormente en la separación de Panamá de Colombia.', 30, 15, 'published', 1);